      ) : (
        <div class="ml-auto flex items-center justify-center gap-8">
          <Link
            class="cursor-pointer text-xl font-bold text-slate-800"
            onClick$={() => signInSig.submit({ redirectTo: "/" })}
          >
            SignIn
          </Link>
        </div>
      )}
    </header>
  );
}

